// === Parse input + validate ===
const input = $input.item.json;
const body = input.body || input;

const question = (body.question || '').toString().trim();
if (!question) {
  throw new Error('ต้องส่ง field "question" ใน JSON body');
}

const sessionId = (body.session_id || body.sessionId || 'default').toString();
const topK = parseInt(body.top_k) || 5;

console.log(`❓ Q: ${question}`);
console.log(`🔑 session: ${sessionId}`);

return {
  json: {
    question,
    session_id: sessionId,
    top_k: topK,
    asked_at: new Date().toISOString()
  }
};

// === Format response สำหรับ webhook ===
const result = $input.item.json;
const parsed = $('Parse Input').item.json;

const answer = (result.output || result.text || '').toString();
const intermediateSteps = result.intermediateSteps || [];

// สกัด tool calls (ค้นด้วย keyword อะไรบ้าง)
const toolCalls = intermediateSteps.map(step => {
  const action = step.action || {};
  return {
    tool: action.tool || '',
    query: action.toolInput?.input || action.toolInput || '',
    observation_length: (step.observation || '').length
  };
});

console.log(`✅ Answer length: ${answer.length}, tool calls: ${toolCalls.length}`);

return {
  json: {
    status: 'success',
    question: parsed.question,
    session_id: parsed.session_id,
    answer,
    tool_calls: toolCalls,
    num_searches: toolCalls.length,
    asked_at: parsed.asked_at,
    responded_at: new Date().toISOString()
  }
};
